1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	};
8	
9	type Item = { type: string };
10	type Step = { type: string; items: Item[] };
11	
12	export function runScenario(steps: Step[]): unknown[] {
13	  return steps.map((step) => ({
14	    premium:
15	      PROCESSING_FEE +
16	      step.items.reduce(
17	        (sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type],
18	        0,
19	      ),
20	  }));
21	}
